var resp = $('본문 블록 조회').first().json;
var blocks = (resp && resp.results) || [];
var texts = [];
var refIds = {};
function scanRich(arr){
  if(!Array.isArray(arr)) return '';
  var s = '';
  for(var i=0;i<arr.length;i++){
    var t = arr[i]; if(!t) continue;
    if(t.type==='mention' && t.mention){
      var mt=t.mention.type;
      if(mt==='page' && t.mention.page && t.mention.page.id) refIds[t.mention.page.id]=1;
      else if(mt==='database' && t.mention.database && t.mention.database.id) refIds[t.mention.database.id]=1;
    }
    if(t.href){ var m=String(t.href).match(/([0-9a-fA-F]{32})/); if(m && /notion\./.test(t.href)) refIds[m[1]]=1; }
    s += (t.plain_text || (t.text && t.text.content)) || '';
  }
  return s;
}
for(var j=0;j<blocks.length;j++){
  var b = blocks[j]; if(!b) continue;
  var type = b.type;
  if(type==='link_to_page' && b.link_to_page){
    if(b.link_to_page.page_id) refIds[b.link_to_page.page_id]=1;
    if(b.link_to_page.database_id) refIds[b.link_to_page.database_id]=1;
    texts.push('[링크된 페이지]');
  } else if(type==='child_page'){
    if(b.id) refIds[b.id]=1;
    texts.push('[하위 페이지: '+((b.child_page && b.child_page.title)||'')+']');
  } else if(type && b[type] && b[type].rich_text){
    texts.push(scanRich(b[type].rich_text));
  } else if(typeof b.content==='string'){
    texts.push(b.content);
  }
}
return [{ json: { bodyBlocks: texts, refIds: Object.keys(refIds) } }];

const coreItems = $input.all();
const coreCards = $('핵심 필터').all().map(function(c){ var p=c.json.properties||{}; return (p.주제 && p.주제.title && p.주제.title[0]) ? p.주제.title[0].plain_text : ''; }).filter(Boolean);
const header = '아래는 보맵 핵심 컨텍스트 카드(' + coreCards.join(', ') + ')의 본문입니다.\n\n';
const coreText = header + coreItems.map(function(b){ return (b.json.content || ''); }).filter(Boolean).join('\n');
const all = $('허브 카드 조회').all();
const detail = all.filter(function(c){ var p=c.json.properties||{}; return p.계층 && p.계층.select && p.계층.select.name === '디테일'; });
const menu = detail.map(function(c){
  var p = c.json.properties || {};
  var subj = (p.주제 && p.주제.title && p.주제.title[0]) ? p.주제.title[0].plain_text : '';
  var area = (p.영역 && p.영역.select) ? p.영역.select.name : '';
  var jobsArr = (p['관련 직무'] && p['관련 직무'].multi_select) ? p['관련 직무'].multi_select.map(function(x){ return x.name; }) : [];
  return '- [' + subj + '] 영역:' + area + ' / 직무:' + jobsArr.join(',') + ' / id:' + c.json.id;
}).join('\n');
return [{ json: { coreContext: coreText, detailMenu: menu } }];

